import React, { useState } from 'react';
import { Box } from 'ink';
import { TextInput } from './input/TextInput.js';
import { List } from './data/List.js';
import { PathInput } from './input/PathInput.js';

/**
 * File Picker recipe — compose TextInput + List + PathInput
 * for a filesystem-aware file selection widget.
 */
export function FilePickerRecipe() {
  const [path, setPath] = useState('');
  const [selected, setSelected] = useState<string | null>(null);

  return (
    <Box flexDirection="column">
      <PathInput
        value={path}
        onChange={setPath}
        placeholder="Enter path..."
      />
      <List
        items={[{ label: 'example.ts', value: 'example.ts' }]}
        onSelect={(item) => setSelected(item.value)}
      />
    </Box>
  );
}
